#include <array>
#include <iostream>

int main()
{
    int M{};
    std::cin >> M;

    std::array<int, 5> arr{};

    for (std::size_t i = 0; i < arr.size(); ++i)
        arr[i] = M * static_cast<int>(i + 1);

    for (std::size_t i = 0; i < arr.size(); ++i)
    {
        if (i > 0) std::cout << ' ';
        std::cout << arr[i];
    }
    std::cout << '\n';

    return 0;
}

