solution_code:
#include <iostream>

int countStartingWith(const char* table[], int size, char target)
{
    int count = 0;
    for (int i = 0; i < size; ++i)
        if (table[i][0] == target)
            ++count;
    return count;
}

int main()
{
    const char* fruits[6] = {
        "apple", "apricot", "banana",
        "avocado", "blueberry", "cherry"
    };

    char ch{};
    std::cin >> ch;

    int result = countStartingWith(fruits, 6, ch);
    std::cout << "Count: " << result << '\n';

    return 0;
}
